local function validate_token(token)
    if not token or token == "" then
        return nil
    end
    
    local parts = {}
    for part in string.gmatch(token, "[^%.]+") do
        table.insert(parts, part)
    end
    
    if #parts ~= 3 then
        return nil
    end
    
    local payload = parts[2]
    local decoded = ngx.decode_base64(payload)
    if not decoded then
        return nil
    end
    
    local cjson = require "cjson"
    local ok, user_data = pcall(cjson.decode, decoded)
    if not ok then
        return nil
    end
    
    return user_data
end

local function has_permission(user_role, required_role)
    if not user_role or not required_role then
        return false
    end
    
    local role_hierarchy = {
        admin = 3,
        moderator = 2,
        user = 1
    }
    
    local user_level = role_hierarchy[user_role] or 0
    local required_level = role_hierarchy[required_role] or 0
    
    return user_level >= required_level
end

local function should_skip_check(uri)
    if not uri then
        return false
    end
    
    if string.find(uri, "/admin", 1, true) then
        return true
    end
    
    if string.find(uri, "/api", 1, true) then
        return true
    end
    
    return false
end

local uri = ngx.var.uri

if should_skip_check(uri) then
    return
end

local auth_header = ngx.var.http_authorization
if not auth_header then
    ngx.status = ngx.HTTP_UNAUTHORIZED
    ngx.header.content_type = "application/json"
    ngx.say('{"error":"Missing authorization header"}')
    return ngx.exit(ngx.HTTP_UNAUTHORIZED)
end

local token = string.match(auth_header, "^Bearer%s+(.+)$")
if not token then
    ngx.status = ngx.HTTP_UNAUTHORIZED
    ngx.header.content_type = "application/json"
    ngx.say('{"error":"Invalid authorization format"}')
    return ngx.exit(ngx.HTTP_UNAUTHORIZED)
end

local user_data = validate_token(token)
if not user_data then
    ngx.status = ngx.HTTP_UNAUTHORIZED
    ngx.header.content_type = "application/json"
    ngx.say('{"error":"Invalid token"}')
    return ngx.exit(ngx.HTTP_UNAUTHORIZED)
end

local user_role = user_data.role
local required_role = ngx.var.required_role or "user"

if not has_permission(user_role, required_role) then
    ngx.status = ngx.HTTP_FORBIDDEN
    ngx.header.content_type = "application/json"
    ngx.say('{"error":"Insufficient permissions"}')
    return ngx.exit(ngx.HTTP_FORBIDDEN)
end

ngx.req.set_header("X-User-Role", user_role)
ngx.req.set_header("X-User-ID", user_data.user_id or "")